"use client";

import * as React from "react";
import type { ColumnDef } from "@gunjo/ui";
import {
  StatGroup,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  DataTable,
  PersonCell,
  Badge,
  Tag,
  Separator,
  SearchInput,
  Select,
  Button,
  EmptyState,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerDescription,
  MetadataList,
  AmountBreakdown,
  ApprovalWorkflow,
  CoSign,
  CoSignBadge,
  SignedRecord,
  ReferenceValue,
  Alert,
  AlertTitle,
  AlertDescription,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  formatCurrency,
  type WorkflowValue,
  type SignedRecordValue,
  type CoSignValue,
} from "@gunjo/ui";
import {
  IconAlertTriangle,
  IconStethoscope,
  IconChevronRight,
  IconHeartbeat,
  IconSmoking,
  IconSmokingNo,
  IconMountain,
  IconBriefcase,
  IconFileText,
} from "@tabler/icons-react";
import {
  APPLICATIONS,
  PRODUCT_LABEL,
  STATUS_LABEL,
  STATUS_BADGE,
  RISK_LABEL,
  RISK_BADGE,
  UNDERWRITERS,
  uwById,
  appByNo,
  BMI_RANGE,
  SBP_RANGE,
  systolic,
  type Application,
  type AssessStatus,
} from "./data";

// 現在ログイン中のアンダーライター（主担当 / 1人目署名）
const ME = UNDERWRITERS[0]; // 新井 美咲

// 査定ワークフローの段階
const STAGES = [
  { id: "queued", label: "受付・告知査定", name: "受付・告知査定" },
  { id: "medical", label: "医的査定", name: "医的査定" },
  { id: "decision", label: "査定結果（標準/条件付/謝絶）", name: "査定結果" },
  { id: "approval", label: "承認", name: "承認" },
  { id: "confirmed", label: "確定", name: "確定" },
];

function fmtMan(n: number): string {
  // 万円表記（一覧の保険金額用）
  if (n === 0) return "—";
  return `${(n / 10000).toLocaleString("ja-JP")}万円`;
}

export default function UnderwritingPage() {
  const [query, setQuery] = React.useState("");
  const [statusFilter, setStatusFilter] = React.useState<"all" | AssessStatus>("all");
  const [openAppNo, setOpenAppNo] = React.useState<string | null>(null);

  // 査定ワークフロー / 署名 / 2名確認の状態（申込番号ごと）
  const [workflows, setWorkflows] = React.useState<Record<string, WorkflowValue>>({});
  const [signed, setSigned] = React.useState<Record<string, SignedRecordValue>>({});
  const [cosigns, setCosigns] = React.useState<Record<string, CoSignValue>>({});
  const [docsChecked, setDocsChecked] = React.useState<Record<string, Record<string, boolean>>>(
    {}
  );

  const rows = React.useMemo(() => {
    const q = query.trim();
    return APPLICATIONS.filter((a) => {
      if (statusFilter !== "all" && a.status !== statusFilter) return false;
      if (!q) return true;
      return (
        a.applicant.includes(q) ||
        a.kana.includes(q) ||
        a.appNo.includes(q) ||
        PRODUCT_LABEL[a.product].includes(q)
      );
    });
  }, [query, statusFilter]);

  // KPI 指標
  const metrics = React.useMemo(() => {
    const queued = APPLICATIONS.filter((a) => a.status === "queued").length;
    const medical = APPLICATIONS.filter((a) => a.status === "medical").length;
    const approvedToday = APPLICATIONS.filter((a) => a.status === "approved").length;
    const condDecl = APPLICATIONS.filter(
      (a) => a.status === "conditional" || a.status === "declined"
    ).length;
    const avgDays = (
      APPLICATIONS.reduce((s, a) => s + a.elapsedDays, 0) / APPLICATIONS.length
    ).toFixed(1);
    const slaOver = APPLICATIONS.filter((a) => a.elapsedDays > a.slaDays).length;
    const needsMed = APPLICATIONS.filter((a) => a.needsMedical && a.status !== "approved").length;
    return { queued, medical, approvedToday, condDecl, avgDays, slaOver, needsMed };
  }, []);

  const active = openAppNo ? appByNo(openAppNo) : undefined;

  const columns = React.useMemo<ColumnDef<Application>[]>(
    () => [
      {
        accessorKey: "appNo",
        header: "申込番号",
        cell: ({ row }) => (
          <div className="font-medium tabular-nums">
            {row.original.appNo}
            {row.original.highValue && (
              <Badge variant="warning" className="ml-2 align-middle">
                高額
              </Badge>
            )}
          </div>
        ),
      },
      {
        accessorKey: "applicant",
        header: "申込者",
        cell: ({ row }) => (
          <PersonCell
            name={row.original.applicant}
            secondary={`${row.original.kana}・${row.original.age}歳 ${row.original.sex}`}
            size="sm"
          />
        ),
      },
      {
        accessorKey: "product",
        header: "商品",
        cell: ({ row }) => (
          <div className="flex flex-col gap-1">
            <span>{PRODUCT_LABEL[row.original.product]}</span>
            {row.original.rider.length > 0 && (
              <span className="text-xs text-muted-foreground">
                特約 {row.original.rider.length}件
              </span>
            )}
          </div>
        ),
      },
      {
        accessorKey: "sumInsured",
        header: "保険金額",
        cell: ({ row }) =>
          row.original.product === "income" ? (
            <span className="tabular-nums">月額20万円</span>
          ) : row.original.product === "medical" ? (
            <span className="tabular-nums">入院日額1万円</span>
          ) : (
            <span className="tabular-nums">{fmtMan(row.original.sumInsured)}</span>
          ),
      },
      {
        id: "disclosure",
        header: "告知",
        cell: ({ row }) =>
          row.original.needsMedical ? (
            <Tag variant="outline" className="gap-1">
              <IconStethoscope className="size-3" aria-hidden />
              要医的審査
            </Tag>
          ) : (
            <span className="text-xs text-muted-foreground">告知のみ</span>
          ),
      },
      {
        accessorKey: "status",
        header: "査定状況",
        cell: ({ row }) => (
          <Badge variant={STATUS_BADGE[row.original.status]}>
            {STATUS_LABEL[row.original.status]}
          </Badge>
        ),
      },
      {
        id: "uw",
        header: "担当",
        cell: ({ row }) => {
          const uw = uwById(row.original.underwriterId);
          return <PersonCell name={uw.name} secondary={uw.role} size="sm" />;
        },
      },
      {
        accessorKey: "elapsedDays",
        header: "経過(SLA)",
        cell: ({ row }) => {
          const over = row.original.elapsedDays > row.original.slaDays;
          return (
            <div className="flex items-center gap-2">
              <span className={over ? "font-semibold text-destructive" : "tabular-nums"}>
                {row.original.elapsedDays}日
              </span>
              {over && (
                <Tag variant="destructive" size="sm">
                  SLA超過
                </Tag>
              )}
            </div>
          );
        },
      },
      {
        id: "open",
        header: "",
        cell: () => (
          <IconChevronRight className="size-4 text-muted-foreground" aria-hidden />
        ),
      },
    ],
    []
  );

  return (
    <main className="mx-auto w-full max-w-7xl px-4 py-6 sm:px-6">
      <header className="mb-6">
        <p className="text-sm text-muted-foreground">生命保険 ／ 引受査定</p>
        <h1 className="text-2xl font-bold tracking-tight">引受査定（アンダーライティング）</h1>
        <p className="mt-1 text-sm text-muted-foreground">
          新規申込の医的・財務査定を行い、リスク区分・特別条件・月払保険料を確定します。
        </p>
      </header>

      {/* サマリ指標 */}
      <StatGroup
        className="mb-6"
        cols={{ base: 2, md: 4, lg: 7 }}
        items={[
          { label: "査定待ち", value: metrics.queued, hint: "未着手の申込" },
          { label: "医的査定中", value: metrics.medical, hint: "医務部 審査中" },
          { label: "本日承認", value: metrics.approvedToday, tone: "positive", trend: "up" },
          {
            label: "条件付・謝絶",
            value: metrics.condDecl,
            tone: metrics.condDecl > 0 ? "negative" : "neutral",
          },
          { label: "平均査定日数", value: `${metrics.avgDays}日` },
          {
            label: "SLA超過",
            value: metrics.slaOver,
            tone: metrics.slaOver > 0 ? "negative" : "neutral",
          },
          { label: "要医的審査", value: metrics.needsMed },
        ]}
      />

      <Card>
        <CardHeader>
          <CardTitle>申込・査定一覧</CardTitle>
          <CardDescription>
            高額・SLA超過・要医的審査の案件を優先して査定します。行を選択すると詳細を開きます。
          </CardDescription>
          <div className="mt-3 flex flex-col gap-2 sm:flex-row sm:items-center">
            <SearchInput
              value={query}
              onValueChange={setQuery}
              placeholder="申込者・申込番号・商品で検索"
              className="sm:max-w-xs"
              aria-label="申込を検索"
            />
            <Select
              label="査定状況で絞り込み"
              className="sm:w-56"
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value as "all" | AssessStatus)}
            >
              <option value="all">すべての査定状況</option>
              {(Object.keys(STATUS_LABEL) as AssessStatus[]).map((s) => (
                <option key={s} value={s}>
                  {STATUS_LABEL[s]}
                </option>
              ))}
            </Select>
          </div>
        </CardHeader>
        <CardContent>
          {rows.length === 0 ? (
            <EmptyState
              title="該当する申込がありません"
              description="検索条件または絞り込みを変更してください。"
            />
          ) : (
            <DataTable
              columns={columns}
              data={rows}
              filter={null}
              pageSize={10}
              onRowClick={(a) => setOpenAppNo(a.appNo)}
              renderCard={(a) => (
                <button
                  type="button"
                  onClick={() => setOpenAppNo(a.appNo)}
                  className="flex w-full flex-col gap-2 rounded-lg border border-border bg-card p-3 text-left"
                >
                  <div className="flex items-center justify-between">
                    <span className="font-medium tabular-nums">{a.appNo}</span>
                    <Badge variant={STATUS_BADGE[a.status]}>{STATUS_LABEL[a.status]}</Badge>
                  </div>
                  <PersonCell
                    name={a.applicant}
                    secondary={`${a.kana}・${a.age}歳 ${a.sex}`}
                    size="sm"
                  />
                  <div className="flex flex-wrap items-center gap-2 text-xs text-muted-foreground">
                    <span>{PRODUCT_LABEL[a.product]}</span>
                    <span>{fmtMan(a.sumInsured)}</span>
                    {a.needsMedical && <Tag variant="outline">要医的審査</Tag>}
                    {a.elapsedDays > a.slaDays && (
                      <Tag variant="destructive" size="sm">
                        SLA超過 {a.elapsedDays}日
                      </Tag>
                    )}
                  </div>
                </button>
              )}
            />
          )}
        </CardContent>
      </Card>

      <Drawer
        open={openAppNo != null}
        onOpenChange={(o) => !o && setOpenAppNo(null)}
        direction="right"
      >
        <DrawerContent side="right" className="w-full max-w-2xl">
          {active && (
            <ApplicationDetail
              app={active}
              workflow={
                workflows[active.appNo] ?? {
                  currentStageId: initialStageForStatus(active.status),
                  status: workflowStatusForApp(active.status),
                }
              }
              onWorkflowChange={(v) =>
                setWorkflows((m) => ({ ...m, [active.appNo]: v }))
              }
              signed={
                signed[active.appNo] ?? {
                  status: active.status === "approved" ? "signed" : "draft",
                  signedBy: active.status === "approved" ? uwById(active.underwriterId).name : undefined,
                  signedAt: active.status === "approved" ? "2026-06-24T09:20:00" : undefined,
                  addenda: [],
                }
              }
              onSignedChange={(v) => setSigned((m) => ({ ...m, [active.appNo]: v }))}
              cosign={cosigns[active.appNo]}
              onCoSign={(v) => setCosigns((m) => ({ ...m, [active.appNo]: v }))}
              docsChecked={docsChecked[active.appNo] ?? {}}
              onToggleDoc={(id, on) =>
                setDocsChecked((m) => ({
                  ...m,
                  [active.appNo]: { ...(m[active.appNo] ?? {}), [id]: on },
                }))
              }
            />
          )}
        </DrawerContent>
      </Drawer>
    </main>
  );
}

function initialStageForStatus(s: AssessStatus): string {
  switch (s) {
    case "queued":
      return "queued";
    case "medical":
      return "medical";
    case "reassess":
      return "medical";
    case "conditional":
    case "declined":
      return "decision";
    case "approved":
      return "confirmed";
    default:
      return "queued";
  }
}
function workflowStatusForApp(s: AssessStatus): WorkflowValue["status"] {
  if (s === "approved") return "approved";
  if (s === "declined") return "rejected";
  return "in-progress";
}

// ---- 申込詳細（ドリルイン）----
function ApplicationDetail({
  app,
  workflow,
  onWorkflowChange,
  signed,
  onSignedChange,
  cosign,
  onCoSign,
  docsChecked,
  onToggleDoc,
}: {
  app: Application;
  workflow: WorkflowValue;
  onWorkflowChange: (v: WorkflowValue) => void;
  signed: SignedRecordValue;
  onSignedChange: (v: SignedRecordValue) => void;
  cosign?: CoSignValue;
  onCoSign: (v: CoSignValue) => void;
  docsChecked: Record<string, boolean>;
  onToggleDoc: (id: string, on: boolean) => void;
}) {
  const uw = uwById(app.underwriterId);
  const d = app.disclosure;
  const sbp = systolic(d.bloodPressure);

  // 必要書類がすべて受領 + チェック済みか（承認の前提）
  const allDocsReady = app.docs.every(
    (doc) => doc.received && (docsChecked[doc.id] ?? false)
  );

  return (
    <div className="flex h-full flex-col overflow-y-auto">
      <DrawerHeader className="border-b border-border">
        <div className="flex items-start justify-between gap-3">
          <div>
            <DrawerTitle className="flex items-center gap-2">
              {app.applicant}
              <Badge variant={RISK_BADGE[app.risk]}>{RISK_LABEL[app.risk]}</Badge>
            </DrawerTitle>
            <DrawerDescription>
              {app.appNo}
              {app.policyNo ? ` ／ 証券番号 ${app.policyNo}` : ""} ・{" "}
              {PRODUCT_LABEL[app.product]}
            </DrawerDescription>
          </div>
          <Badge variant={STATUS_BADGE[app.status]}>{STATUS_LABEL[app.status]}</Badge>
        </div>
        {app.highValue && (
          <Alert variant="warning" className="mt-3 flex items-start gap-2">
            <IconAlertTriangle className="mt-0.5 size-4 shrink-0" aria-hidden />
            <div>
              <AlertTitle>高額契約 — 2名承認が必要です</AlertTitle>
              <AlertDescription>
                保険金額 {fmtMan(app.sumInsured)} ／ 主担当の確定に加え、別のアンダーライターによる2人確認（CoSign）を行ってください。
              </AlertDescription>
            </div>
          </Alert>
        )}
      </DrawerHeader>

      <div className="px-4 py-4 sm:px-6">
        <Tabs defaultValue="overview">
          <TabsList>
            <TabsTrigger value="overview">概要</TabsTrigger>
            <TabsTrigger value="risk">告知・リスク</TabsTrigger>
            <TabsTrigger value="premium">保険料算定</TabsTrigger>
            <TabsTrigger value="approval">承認・確定</TabsTrigger>
            <TabsTrigger value="history">査定履歴</TabsTrigger>
          </TabsList>

          {/* 概要 */}
          <TabsContent value="overview">
            <MetadataList
              items={[
                { label: "申込番号", value: app.appNo },
                { label: "申込者", value: `${app.applicant}（${app.kana}）` },
                { label: "年齢・性別", value: `${app.age}歳 ${app.sex}` },
                { label: "商品", value: PRODUCT_LABEL[app.product] },
                {
                  label: "保険金額",
                  value:
                    app.product === "income"
                      ? "収入保障 月額20万円"
                      : app.product === "medical"
                      ? "入院日額1万円"
                      : fmtMan(app.sumInsured),
                },
                { label: "特約", value: app.rider.length ? app.rider.join("／") : "なし" },
                {
                  label: "月払保険料",
                  value:
                    app.monthlyPremium > 0 ? formatCurrency(app.monthlyPremium) : "—（謝絶）",
                },
                {
                  label: "担当アンダーライター",
                  value: `${uw.name}（${uw.role}・${uw.team}）`,
                },
                {
                  label: `経過日数（SLA基準 ${app.slaDays}日）`,
                  value:
                    app.elapsedDays > app.slaDays
                      ? `${app.elapsedDays}日（SLA超過）`
                      : `${app.elapsedDays}日`,
                },
              ]}
            />
          </TabsContent>

          {/* 告知・リスク評価 */}
          <TabsContent value="risk">
            <div className="space-y-4">
              <section>
                <h3 className="mb-2 text-sm font-semibold">告知サマリ（健康状態）</h3>
                <div className="grid grid-cols-2 gap-3">
                  <Card>
                    <CardContent className="p-3">
                      <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                        <IconHeartbeat className="size-3.5" aria-hidden /> BMI
                      </div>
                      <div className="mt-1 text-lg font-semibold">
                        <ReferenceValue
                          value={d.bmi}
                          range={BMI_RANGE}
                          unit=""
                          showLabel
                          format={(v) => v.toFixed(1)}
                        />
                      </div>
                      <p className="mt-1 text-xs text-muted-foreground">
                        {d.height}cm / {d.weight}kg（基準18.5–25）
                      </p>
                    </CardContent>
                  </Card>
                  <Card>
                    <CardContent className="p-3">
                      <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                        <IconHeartbeat className="size-3.5" aria-hidden /> 血圧（収縮期）
                      </div>
                      <div className="mt-1 text-lg font-semibold">
                        <ReferenceValue
                          value={sbp}
                          range={SBP_RANGE}
                          unit="mmHg"
                          showLabel
                        />
                      </div>
                      <p className="mt-1 text-xs text-muted-foreground">
                        測定値 {d.bloodPressure}
                      </p>
                    </CardContent>
                  </Card>
                </div>
              </section>

              <section>
                <h3 className="mb-2 text-sm font-semibold">喫煙・危険職業・危険趣味</h3>
                <div className="flex flex-wrap gap-2">
                  <Tag variant={d.smoker ? "destructive" : "outline"} className="gap-1">
                    {d.smoker ? (
                      <IconSmoking className="size-3" aria-hidden />
                    ) : (
                      <IconSmokingNo className="size-3" aria-hidden />
                    )}
                    {d.smoker ? `喫煙：あり（${d.smokingNote ?? ""}）` : "非喫煙"}
                  </Tag>
                  {d.hazardousJob && (
                    <Tag variant="destructive" className="gap-1">
                      <IconBriefcase className="size-3" aria-hidden />
                      危険職業：{d.hazardousJob}
                    </Tag>
                  )}
                  {d.hazardousHobby && (
                    <Tag variant="destructive" className="gap-1">
                      <IconMountain className="size-3" aria-hidden />
                      危険趣味：{d.hazardousHobby}
                    </Tag>
                  )}
                </div>
              </section>

              <section>
                <h3 className="mb-2 text-sm font-semibold">既往症・治療歴</h3>
                {d.history.length === 0 ? (
                  <p className="text-sm text-muted-foreground">告知された既往症はありません。</p>
                ) : (
                  <ul className="list-disc space-y-1 pl-5 text-sm">
                    {d.history.map((h, i) => (
                      <li key={i}>{h}</li>
                    ))}
                  </ul>
                )}
                {d.notes && (
                  <p className="mt-2 rounded-md bg-muted p-2 text-sm text-muted-foreground">
                    {d.notes}
                  </p>
                )}
              </section>

              <Separator />

              <section>
                <h3 className="mb-2 text-sm font-semibold">リスク評価（査定結果）</h3>
                <div className="flex items-center gap-2">
                  <Badge variant={RISK_BADGE[app.risk]}>{RISK_LABEL[app.risk]}</Badge>
                </div>
                {app.riskDetail && (
                  <Alert
                    variant={app.risk === "declined" ? "destructive" : "warning"}
                    className="mt-2 flex items-start gap-2"
                  >
                    <IconAlertTriangle className="mt-0.5 size-4 shrink-0" aria-hidden />
                    <AlertDescription>{app.riskDetail}</AlertDescription>
                  </Alert>
                )}
              </section>
            </div>
          </TabsContent>

          {/* 保険料算定 */}
          <TabsContent value="premium">
            <Card>
              <CardHeader>
                <CardTitle className="text-base">月払保険料の算定</CardTitle>
                <CardDescription>
                  基本保険料 ＋ 特約 ＋ 健康状態割増（特別条件）− 各種割引 = 月払保険料
                </CardDescription>
              </CardHeader>
              <CardContent>
                <AmountBreakdown
                  lines={app.premiumLines}
                  total={{
                    label: "月払保険料",
                    amount: app.monthlyPremium,
                    tone: app.monthlyPremium === 0 ? "negative" : "neutral",
                  }}
                  formula={app.premiumFormula}
                />
              </CardContent>
            </Card>
          </TabsContent>

          {/* 承認・確定 */}
          <TabsContent value="approval">
            <div className="space-y-5">
              <section>
                <h3 className="mb-2 text-sm font-semibold">必要書類</h3>
                <ul className="space-y-1.5">
                  {app.docs.map((doc) => (
                    <li
                      key={doc.id}
                      className="flex items-center justify-between gap-3 rounded-md border border-border px-3 py-2"
                    >
                      <label className="flex items-center gap-2 text-sm">
                        <input
                          type="checkbox"
                          className="size-4"
                          disabled={!doc.received}
                          checked={docsChecked[doc.id] ?? false}
                          onChange={(e) => onToggleDoc(doc.id, e.target.checked)}
                        />
                        <IconFileText className="size-4 text-muted-foreground" aria-hidden />
                        {doc.label}
                      </label>
                      <Badge variant={doc.received ? "success" : "outline"}>
                        {doc.received ? "受領済" : "未受領"}
                      </Badge>
                    </li>
                  ))}
                </ul>
              </section>

              <Separator />

              <section>
                <h3 className="mb-2 text-sm font-semibold">査定ワークフロー</h3>
                <ApprovalWorkflow
                  stages={STAGES}
                  value={workflow}
                  onChange={onWorkflowChange}
                  actor={ME.name}
                  canAdvance={allDocsReady}
                  advanceHint={
                    allDocsReady ? undefined : "必要書類の受領・確認が完了していません"
                  }
                />
              </section>

              <Separator />

              <section>
                <h3 className="mb-2 text-sm font-semibold">査定の確定（署名・確定後ロック）</h3>
                <SignedRecord
                  value={signed}
                  onChange={onSignedChange}
                  signerId={ME.name}
                  canSign={allDocsReady && app.status !== "declined"}
                >
                  {({ readOnly }) => (
                    <div className="text-sm text-muted-foreground">
                      {readOnly
                        ? "この査定結果は確定・ロックされています。修正は追記（addendum）で行ってください。"
                        : "必要書類の確認後に署名すると、査定結果が確定し編集がロックされます。"}
                    </div>
                  )}
                </SignedRecord>
              </section>

              {app.highValue && (
                <>
                  <Separator />
                  <section>
                    <div className="mb-2 flex items-center justify-between">
                      <h3 className="text-sm font-semibold">2名承認（高額・特別条件）</h3>
                      <CoSignBadge value={cosign} />
                    </div>
                    <CoSign
                      primaryId={ME.name}
                      requireReason
                      value={cosign}
                      onSign={onCoSign}
                      attestations={[
                        { id: "a1", label: "保険金額・特別条件の内容を確認した" },
                        { id: "a2", label: "医的査定・告知内容に矛盾がないことを確認した" },
                      ]}
                      reasonLabel="確認コメント"
                    />
                  </section>
                </>
              )}
            </div>
          </TabsContent>

          {/* 査定履歴 */}
          <TabsContent value="history">
            <Timeline>
              {app.history.map((h, i) => (
                <TimelineItem
                  key={i}
                  variant={i === app.history.length - 1 ? "active" : "default"}
                  connector={i !== app.history.length - 1}
                >
                  <TimelineTime>{h.at}</TimelineTime>
                  <TimelineTitle>{h.actor}</TimelineTitle>
                  <TimelineDescription>{h.text}</TimelineDescription>
                </TimelineItem>
              ))}
            </Timeline>
          </TabsContent>
        </Tabs>
      </div>
    </div>
  );
}
